[ 'message' => 'Login Successful', 'token' => $token, 'name' => $user['name'], 'role' => $role, 'account_type' => $accountType, 'education_level' => $educationLevel, 'promo_discount' => $promoDiscount, 'verification_status' => $verificationStatus, 'subscription_tier' => $user['subscription_tier'] ?? 'free', 'subscription_expires_at' => $user['subscription_expires_at'] ?? null, 'profile_image_path' => $user['profile_image_path'] ?? null, ], 200); } private function trackDeviceSession(array $user, string $ipAddress): void { $db = \Config\Database::connect(); $userAgent = (string) ($this->request->getServer('HTTP_USER_AGENT') ?? ''); $deviceName = parseDeviceName($userAgent); $location = $this->getIpLocation($ipAddress); $existing = $db->table('user_sessions') ->where('user_id', $user['user_id']) ->where('device_name', $deviceName) ->where('ip_address', $ipAddress) ->get() ->getRowArray(); if ($existing) { $db->table('user_sessions') ->where('session_id', $existing['session_id']) ->update(['last_login_at' => date('Y-m-d H:i:s')]); return; } $anyTrusted = $db->table('user_sessions') ->where('user_id', $user['user_id']) ->where('is_trusted', 1) ->countAllResults(); $isNewDevice = $anyTrusted > 0; $db->table('user_sessions')->insert([ 'user_id' => $user['user_id'], 'ip_address' => $ipAddress, 'user_agent' => substr($userAgent, 0, 255), 'device_name' => $deviceName, 'location' => $location, 'is_trusted' => $isNewDevice ? 0 : 1, 'last_login_at' => date('Y-m-d H:i:s'), ]); if ($isNewDevice) { $this->sendNewDeviceAlert($user, $deviceName, $ipAddress, $location); } } private function getIpLocation(string $ip): string { if ($ip === '::1' || $ip === '127.0.0.1') { return 'Localhost'; } static $cache = []; if (isset($cache[$ip])) { return $cache[$ip]; } try { $ctx = stream_context_create(['http' => ['timeout' => 3, 'method' => 'GET']]); $response = file_get_contents("http://ip-api.com/json/{$ip}?fields=city,region,country", false, $ctx); if ($response) { $data = json_decode($response, true); if (! empty($data['city']) && ! empty($data['country'])) { $location = trim("{$data['city']}, {$data['region']}, {$data['country']}", ', '); $cache[$ip] = $location; return $location; } } } catch (\Throwable $e) { log_message('info', "IP location lookup failed for {$ip}: " . $e->getMessage()); } $cache[$ip] = 'Unknown'; return 'Unknown'; } private function sendNewDeviceAlert(array $user, string $deviceName, string $ipAddress, string $location): void { try { $db = \Config\Database::connect(); $db->table('notifications')->insert([ 'user_id' => $user['user_id'], 'title' => 'New Device Sign-In', 'message' => "A new device signed into your account: {$deviceName} ({$ipAddress} - {$location}). If this wasn't you, reset your password immediately.", ]); $emailService = new EmailService(); $emailService->sendNewDeviceAlert( $user['email'], $user['name'], $deviceName, $ipAddress, $location ); } catch (\Throwable $e) { log_message('error', 'Failed to send new device alert: ' . $e->getMessage()); } } public function sendVerificationCode() { FeatureSchema::ensure(); $email = trim((string) ($this->request->getVar('email') ?? '')); if ($email === '' || ! filter_var($email, FILTER_VALIDATE_EMAIL)) { return $this->respond(['error' => 'A valid email address is required.'], 400); } $db = \Config\Database::connect(); $userModel = new UserModel(); $existing = $userModel->where('email', $email)->first(); if ($existing && (bool)($existing['email_verified'] ?? 1)) { return $this->respond(['error' => 'This email is already registered and verified.'], 409); } $recentCount = $db->table('verification_codes') ->where('email', $email) ->where('type', 'email_verify') ->where('created_at >=', date('Y-m-d H:i:s', strtotime('-1 hour'))) ->countAllResults(); if ($recentCount >= 3) { return $this->respond(['error' => 'Too many verification requests. Please try again in 1 hour.'], 429); } $db->table('verification_codes') ->where('email', $email) ->where('type', 'email_verify') ->where('used', 0) ->update(['used' => 1]); $code = generateOtpCode(); $expiresAt = date('Y-m-d H:i:s', strtotime('+15 minutes')); $db->table('verification_codes')->insert([ 'email' => $email, 'code' => $code, 'type' => 'email_verify', 'expires_at' => $expiresAt, ]); try { $emailService = new EmailService(); $emailService->sendVerificationCode($email, $code); } catch (\Throwable $e) { log_message('error', 'Failed to send verification email: ' . $e->getMessage()); return $this->respond(['error' => 'Failed to send verification email. Please try again.'], 500); } return $this->respond(['message' => 'Verification code sent to your email.']); } public function verifyEmail() { FeatureSchema::ensure(); $email = trim((string) ($this->request->getVar('email') ?? '')); $code = trim((string) ($this->request->getVar('code') ?? '')); if ($email === '' || $code === '') { return $this->respond(['error' => 'Email and verification code are required.'], 400); } $db = \Config\Database::connect(); $record = $db->table('verification_codes') ->where('email', $email) ->where('code', $code) ->where('type', 'email_verify') ->where('used', 0) ->orderBy('created_at', 'DESC') ->get() ->getRowArray(); if (! $record) { return $this->respond(['error' => 'Invalid or expired verification code.'], 400); } if (isOtpExpired($record['expires_at'])) { $db->table('verification_codes') ->where('code_id', $record['code_id']) ->update(['used' => 1]); return $this->respond(['error' => 'Verification code has expired. Request a new one.'], 400); } $db->table('verification_codes') ->where('code_id', $record['code_id']) ->update(['used' => 1]); $userModel = new UserModel(); $user = $userModel->where('email', $email)->first(); if ($user) { $userModel->update($user['user_id'], ['email_verified' => 1]); } return $this->respond([ 'message' => 'Email verified successfully. You can now complete registration.', 'email_verified' => true, ]); } public function forgotPassword() { FeatureSchema::ensure(); $email = trim((string) ($this->request->getVar('email') ?? '')); if ($email === '' || ! filter_var($email, FILTER_VALIDATE_EMAIL)) { return $this->respond(['error' => 'A valid email address is required.'], 400); } $userModel = new UserModel(); $user = $userModel->where('email', $email)->first(); if (! $user) { return $this->respond(['error' => 'No account found with this email address.'], 404); } $db = \Config\Database::connect(); $recentCount = $db->table('verification_codes') ->where('email', $email) ->where('type', 'password_reset') ->where('created_at >=', date('Y-m-d H:i:s', strtotime('-1 hour'))) ->countAllResults(); if ($recentCount >= 3) { return $this->respond(['error' => 'Too many password reset requests. Please try again in 1 hour.'], 429); } $db->table('verification_codes') ->where('email', $email) ->where('type', 'password_reset') ->where('used', 0) ->update(['used' => 1]); $code = generateOtpCode(); $expiresAt = date('Y-m-d H:i:s', strtotime('+15 minutes')); $db->table('verification_codes')->insert([ 'email' => $email, 'code' => $code, 'type' => 'password_reset', 'expires_at' => $expiresAt, ]); try { $emailService = new EmailService(); $emailService->sendPasswordResetCode($email, $code); } catch (\Throwable $e) { log_message('error', 'Failed to send password reset email: ' . $e->getMessage()); return $this->respond(['error' => 'Failed to send reset email. Please try again.'], 500); } return $this->respond(['message' => 'Password reset code sent to your email.']); } public function resetPassword() { FeatureSchema::ensure(); $email = trim((string) ($this->request->getVar('email') ?? '')); $code = trim((string) ($this->request->getVar('code') ?? '')); $newPassword = (string) ($this->request->getVar('new_password') ?? ''); if ($email === '' || $code === '' || $newPassword === '') { return $this->respond(['error' => 'Email, code, and new password are required.'], 400); } if (strlen($newPassword) < 6) { return $this->respond(['error' => 'Password must be at least 6 characters.'], 400); } $db = \Config\Database::connect(); $record = $db->table('verification_codes') ->where('email', $email) ->where('code', $code) ->where('type', 'password_reset') ->where('used', 0) ->orderBy('created_at', 'DESC') ->get() ->getRowArray(); if (! $record) { return $this->respond(['error' => 'Invalid or expired reset code.'], 400); } if (isOtpExpired($record['expires_at'])) { $db->table('verification_codes') ->where('code_id', $record['code_id']) ->update(['used' => 1]); return $this->respond(['error' => 'Reset code has expired. Request a new one.'], 400); } $userModel = new UserModel(); $user = $userModel->where('email', $email)->first(); if (! $user) { return $this->respond(['error' => 'User not found.'], 404); } $userModel->update($user['user_id'], ['password' => $newPassword]); $db->table('verification_codes') ->where('code_id', $record['code_id']) ->update(['used' => 1]); return $this->respond(['message' => 'Password reset successful. You can now log in with your new password.']); } public function resendCode() { FeatureSchema::ensure(); $email = trim((string) ($this->request->getVar('email') ?? '')); $type = trim((string) ($this->request->getVar('type') ?? 'email_verify')); if ($email === '' || ! in_array($type, ['email_verify', 'password_reset'], true)) { return $this->respond(['error' => 'Valid email and type (email_verify or password_reset) are required.'], 400); } $db = \Config\Database::connect(); $lastCode = $db->table('verification_codes') ->where('email', $email) ->where('type', $type) ->where('used', 0) ->orderBy('created_at', 'DESC') ->get() ->getRowArray(); if ($lastCode) { $lastAttempt = strtotime($lastCode['created_at']); $attempts = (int) $lastCode['attempts']; if ($attempts >= 1) { $db->table('verification_codes') ->where('code_id', $lastCode['code_id']) ->update(['used' => 1]); } else { $db->table('verification_codes') ->where('code_id', $lastCode['code_id']) ->update(['attempts' => 1]); return $this->respond(['message' => 'Verification code already