n $this->respond(['message' => 'Device marked as trusted.']); } public function revokeSession($sessionId = null) { $user = $this->getAuthUser(); if (! $user) return $this->failUnauthorized(); $db = \Config\Database::connect(); $db->table('user_sessions') ->where('session_id', $sessionId) ->where('user_id', $user['user_id']) ->delete(); return $this->respondDeleted(['message' => 'Session revoked.']); } private function getAuthUser(): ?array { $header = $this->request->getHeaderLine('Authorization'); $decoded = \App\Libraries\JwtAuth::decodeFromHeader($header); if (! $decoded || empty($decoded->uid)) { return null; } $userModel = new UserModel(); return $userModel->find((int) $decoded->uid); } } 
